--
-- Estructura para la vista `api_web`
--
DROP TABLE IF EXISTS `api_web`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `api_web`  AS  select `f`.`codfactura` AS `codfactura`,`f`.`fecha` AS `fecha`,`f`.`codpaciente` AS `codpaciente`,`p`.`nombre` AS `nombre`,`p`.`nif` AS `nif`,substr(md5(`p`.`nif`),1,8) AS `apikey`,`f`.`saldo` AS `saldo`,`f`.`condicion` AS `condicion` from (`saci_ad`.`facturas` `f` join `saci_ad`.`clientes` `p` on((`p`.`codcliente` = `f`.`codpaciente`))) where (`f`.`borrado` = 0) order by `f`.`codfactura` desc ;

-- --------------------------------------------------------

--
-- Estructura para la vista `listas_precio_duplicado`
--
DROP TABLE IF EXISTS `listas_precio_duplicado`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `listas_precio_duplicado`  AS  select `saci_ad`.`listas_precio`.`idlista_precio` AS `idlista_precio`,`saci_ad`.`listas_precio`.`idexa` AS `idexa`,concat(`saci_ad`.`listas_precio`.`detalle`,' DUPLICADO') AS `detalle`,`saci_ad`.`listas_precio`.`valor` AS `valor`,`saci_ad`.`listas_precio`.`codcliente` AS `codcliente`,`saci_ad`.`listas_precio`.`nocturno` AS `nocturno`,`saci_ad`.`listas_precio`.`ff` AS `ff`,`saci_ad`.`listas_precio`.`borrado` AS `borrado` from `saci_ad`.`listas_precio` ;

