-- Estructura para la vista `vista_articulos`
--
DROP TABLE IF EXISTS `vista_articulos`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_articulos`  AS  select `e`.`id` AS `id`,`e`.`IDExa` AS `idexa`,`e`.`Nom_exa` AS `nom_exa`,`e`.`codfamilia` AS `codfamilia`,`f`.`nombre` AS `nombrefamilia`,`t`.`tipo_art` AS `tipo_art`,`t`.`venta` AS `venta` from ((`saci_ad`.`examenes` `e` join `saci_ad`.`familias` `f`) join `saci_ad`.`tipos_art` `t`) where ((1 = 1) and (`e`.`codfamilia` = `f`.`codfamilia`) and (`e`.`borrado` = 0) and (`t`.`codta` = `e`.`codta`)) order by `e`.`codfamilia`,`e`.`Nom_exa` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_formatos`
--
DROP TABLE IF EXISTS `vista_formatos`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_formatos`  AS  (select `saci_ad`.`campos`.`IDFor` AS `IDFor`,`saci_ad`.`campos`.`IDCam` AS `id`,'C' AS `tipo`,`saci_ad`.`campos`.`tab_cam` AS `tab`,concat('campo-',`saci_ad`.`campos`.`IDCam`) AS `nombre`,`saci_ad`.`campos`.`PosX` AS `PosX`,`saci_ad`.`campos`.`PosY` AS `PosY`,`saci_ad`.`campos`.`Ancho_cam` AS `Ancho`,`saci_ad`.`campos`.`Alto_cam` AS `Alto`,`saci_ad`.`campos`.`Tipo_cam` AS `type`,`saci_ad`.`campos`.`TamFue_cam` AS `tam`,`saci_ad`.`campos`.`NegFue_cam` AS `neg`,`saci_ad`.`campos`.`Def_cam` AS `valor`,`saci_ad`.`campos`.`For_cam` AS `formato` from `saci_ad`.`campos` where (`saci_ad`.`campos`.`printer` = 'True')) union (select `saci_ad`.`listas`.`IDFor` AS `IDFor`,`saci_ad`.`listas`.`Idlis` AS `id`,'L' AS `tipo`,`saci_ad`.`listas`.`tab_lis` AS `tab`,concat('select-',`saci_ad`.`listas`.`Idlis`) AS `nombre`,`saci_ad`.`listas`.`PosX` AS `PosX`,`saci_ad`.`listas`.`PosY` AS `PosY`,`saci_ad`.`listas`.`Ancho_lis` AS `Ancho`,0 AS `Alto`,'' AS `type`,`saci_ad`.`listas`.`TamFue_lis` AS `tam`,`saci_ad`.`listas`.`NegFue_lis` AS `neg`,`saci_ad`.`listas`.`Valor_lis` AS `valor`,'' AS `formato` from `saci_ad`.`listas` where (`saci_ad`.`listas`.`printer` = 'True')) ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_listas_precios`
--
DROP TABLE IF EXISTS `vista_listas_precios`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_listas_precios`  AS  select `l`.`idlista_precio` AS `idlista_precio`,`l`.`idexa` AS `idexa`,`e`.`Nom_exa` AS `nom_exa`,`l`.`detalle` AS `detalle`,`l`.`valor` AS `valor`,`l`.`codcliente` AS `codcliente`,`c`.`nombre` AS `nombre`,`l`.`nocturno` AS `nocturno`,`l`.`ff` AS `ff` from ((`saci_ad`.`listas_precio` `l` join `saci_ad`.`examenes` `e` on((`e`.`IDExa` = convert(`l`.`idexa` using utf8)))) join `saci_ad`.`clientes` `c` on((`c`.`codcliente` = `l`.`codcliente`))) where (`l`.`borrado` = 0) ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_lista_precios`
--
DROP TABLE IF EXISTS `vista_lista_precios`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_lista_precios`  AS  select `l`.`idlista_precio` AS `idlista_precio`,`l`.`idexa` AS `idexa`,`e`.`Nom_exa` AS `nom_exa`,`e`.`codfamilia` AS `codfamilia`,`f`.`nombre` AS `nombre`,`l`.`valor` AS `valor`,`l`.`detalle` AS `detalle`,`l`.`codcliente` AS `codcliente`,if((`l`.`codcliente` = 0),'TODOS LOS CLIENTES',(select `c`.`nombre` from `saci_ad`.`clientes` `c` where (`c`.`codcliente` = `l`.`codcliente`))) AS `cliente`,`l`.`nocturno` AS `nocturno`,`l`.`ff` AS `ff` from ((`saci_ad`.`listas_precio` `l` join `saci_ad`.`examenes` `e`) join `saci_ad`.`familias` `f`) where ((`l`.`borrado` = 0) and (`e`.`IDExa` = convert(`l`.`idexa` using utf8)) and (`f`.`codfamilia` = `e`.`codfamilia`)) order by `e`.`Nom_exa` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_ordenes_procesar`
--
DROP TABLE IF EXISTS `vista_ordenes_procesar`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_ordenes_procesar`  AS  select distinct `f`.`codfactura` AS `codfactura`,`p`.`nombre` AS `nombre`,`p`.`sexo` AS `sexo`,(select timestampdiff(YEAR,`c`.`fn`,curdate())) AS `anios`,(select (timestampdiff(MONTH,`p`.`fn`,curdate()) - (timestampdiff(YEAR,`p`.`fn`,curdate()) * 12))) AS `meses`,`f`.`fecha` AS `fecha`,`f`.`codcliente` AS `codcliente`,`c`.`empresa` AS `empresa` from (((`saci_ad`.`facturas` `f` join `saci_ad`.`factulinea` `fl`) join `saci_ad`.`clientes` `c`) join `saci_ad`.`clientes` `p`) where ((`f`.`borrado` = 0) and (`fl`.`codfactura` = `f`.`codfactura`) and (`fl`.`status` = 1) and (`p`.`codcliente` = `f`.`codpaciente`) and (`c`.`codcliente` = `f`.`codcliente`)) ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_resultados_pacientes`
--
DROP TABLE IF EXISTS `vista_resultados_pacientes`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_resultados_pacientes`  AS  select distinct `fl`.`codfactura` AS `codfactura`,`c`.`nombre` AS `nombre`,`c`.`nif` AS `nif`,substr(md5(`c`.`nif`),1,8) AS `apikey`,`c`.`sexo` AS `sexo`,`c`.`fn` AS `fn`,`f`.`fecha` AS `fecha`,`fl`.`status` AS `status`,`s`.`saldo` AS `saldo` from ((((`saci_ad`.`factulinea` `fl` join `saci_ad`.`facturas` `f`) join `saci_ad`.`clientes` `c`) join `saci_ad`.`examenes` `e`) join `saci_ad`.`vista_saldo` `s`) where ((`f`.`codfactura` = `fl`.`codfactura`) and (`fl`.`status` = 3) and (`f`.`borrado` = 0) and (`c`.`codcliente` = `f`.`codpaciente`) and (`e`.`IDExa` = `fl`.`codigo`) and (`s`.`codfactura` = `fl`.`codfactura`)) order by `fl`.`codfactura` desc ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_result_fact_exa`
--
DROP TABLE IF EXISTS `vista_result_fact_exa`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_result_fact_exa`  AS  select `r`.`codfactura` AS `codfactura`,`r`.`codexamen` AS `codexamen`,`r`.`numlinea` AS `numlinea` from `saci_ad`.`resultados` `r` group by `r`.`codfactura`,`r`.`codexamen`,`r`.`numlinea` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_saldo`
--
DROP TABLE IF EXISTS `vista_saldo`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_saldo`  AS  select `f`.`codfactura` AS `codfactura`,`f`.`codcliente` AS `codcliente`,`f`.`totalfactura` AS `total`,ifnull(sum(`c`.`importe`),0) AS `pagado`,(`f`.`totalfactura` - ifnull(sum(`c`.`importe`),0)) AS `saldo` from (`saci_ad`.`facturas` `f` left join `saci_ad`.`cobros` `c` on((`f`.`codfactura` = `c`.`codfactura`))) where (`f`.`borrado` = 0) group by `f`.`codfactura`,`c`.`codfactura` order by `f`.`codfactura` desc ;
COMMIT;

