(892, 'PROTEINAS TOTALES Y FRACCIONADA IEQ', '27/05/2007 0:00', 'aperez', '-', '*NULL', '4,5', 0, 'function calculo(){\n      valor1=document.getElementById(\"campo-0\").value - document.getElementById(\"campo-1\").value;\n      document.getElementById(\"campo-2\").value= Math.round(valor1 * 100) / 100;\n      valor2=document.getElementById(\"campo-1\").value / document.getElementById(\"campo-2\").value;\n      document.getElementById(\"campo-3\").value= Math.round(valor2 * 100) / 100;\n    }', 'function calculo(codfactura,numlinea){\n      document.getElementById(\"campo-2.\"+codfactura+\"-\"+numlinea).value= Math.round( document.getElementById(\"campo-0-\"+codfactura+\"-\"+numlinea).value - document.getElementById(\"campo-1-\"+codfactura+\"-\"+numlinea).value )/100;\n    \ndocument.getElementById(\"campo-3-\"+codfactura+\"-\"+numlinea).value= Math.round( document.getElementById(\"campo-1-\"+codfactura+\"-\"+numlinea).value / document.getElementById(\"campo-2-\"+codfactura+\"-\"+numlinea).value *100)/100;\n    }', 0),
